def extract_xml_info(root: etree._Element) -> Dict[str, Any]:
    """
    Extract basic information from a parsed XML element tree.
    
    Args:
        root: The root element of the parsed XML.
        
    Returns:
        Dictionary containing XML document information.
    """
    def count_elements(element):
        count = 1
        for child in element:
            count += count_elements(child)
        return count
    
    def get_namespaces(element):
        namespaces = set()
        for elem in element.iter():
            if elem.tag and '}' in elem.tag:
                ns = elem.tag.split('}')[0].strip('{')
                namespaces.add(ns)
        return list(namespaces)
    
    return {
        'root_tag': root.tag,
        'root_attributes': dict(root.attrib),
        'total_elements': count_elements(root),
        'direct_children': len(root),
        'namespaces': get_namespaces(root),
        'text_content_preview': (root.text or '').strip()[:200] if root.text else None,
    }


